'use client';
import { useEffect, useState, } from 'react';
import { type Dispatch, type SetStateAction } from 'react'
import { FileCard } from './_components/file-card';
import FilesPageDTO from 'api/src/dto/files-page-dto';

export default function MainPage() {
  const [filesPage, setFilesPage] = useState<FilesPageDTO>();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchFiles(setFilesPage, setLoading, setError);
  }, []);



  if (loading) return <div>Загрузка...</div>;
  if (error) return <div>Ошибка: {error}</div>;
  if (!filesPage || filesPage.items.length === 0) return <div>Нет файлов</div>;

  return (
    <html>
      <body>
        <h1>Список загруженных файлов</h1>
        <ul>
          {filesPage.items.map((file) => (
            <li key={file.id}>
              <FileCard metadata={file} />
            </li>
          ))}
        </ul>
      </body>
    </html>
  );
}

async function fetchFiles(
  setFilesPage: Dispatch<SetStateAction<FilesPageDTO | undefined>>,
  setLoading: Dispatch<SetStateAction<boolean>>,
  setError: Dispatch<SetStateAction<string | null>>) {
  setLoading(true);
  setError(null);
  try {
    const apiUrl = process.env.NEXT_PUBLIC_API_URL;
    if (!apiUrl) throw new Error('NEXT_PUBLIC_API_URL is not defined');

    const response = await fetch(`${apiUrl}/api/files/`);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    const data: FilesPageDTO = await response.json();
    setFilesPage(data);
  } catch (err) {
    setError(err instanceof Error ? err.message : 'Ошибка загрузки');
    console.error(err);
  } finally {
    setLoading(false);
  }
};